import { useState } from "react";
import "./App.css";

export default function App() {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const handleModal = function () {
        setIsModalOpen(!isModalOpen);
    };

    return (
        <div className="App">
            <Header />
            <TodoBox isModalOpen={isModalOpen} handleModal={handleModal} />
            <Modal isModalOpen={isModalOpen} handleModal={handleModal}>
                <TodoModal />
            </Modal>
        </div>
    );
}
const Header = function () {
    return (
        <>
            <header className="header">
                <h1>Todoアプリ</h1>
            </header>
        </>
    );
};
const TodoBox = function ({ isModalOpen, handleModal }) {
    return (
        <>
            <div className="todo-box">
                <Card isModalOpen={isModalOpen} handleModal={handleModal}>
                    <AddCard />
                </Card>
            </div>
        </>
    );
};
const Card = function ({ cl, children }) {
    return <div className={`${cl} card--layout`}>{children}</div>;
};
const AddCard = function ({ isModalOpen, handleModal }) {
    return (
        <div className="add-card__box">
            <p className="add-card--text">追加</p>
            <button type="button" className="add-card__btn" onClick={handleModal}>
                <svg
                    xmlns="http://www.w3.org/2000/svg"
                    viewBox="0 0 24 24"
                    fill="currentColor"
                    className="add-card__icon"
                >
                    <path
                        fill-rule="evenodd"
                        d="M12 3.75a.75.75 0 0 1 .75.75v6.75h6.75a.75.75 0 0 1 0 1.5h-6.75v6.75a.75.75 0 0 1-1.5 0v-6.75H4.5a.75.75 0 0 1 0-1.5h6.75V4.5a.75.75 0 0 1 .75-.75Z"
                        clip-rule="evenodd"
                    />
                </svg>
            </button>
        </div>
    );
};
const TodoCard = function () {
    return <></>;
};
const Modal = function ({ isModalOpen, handleModal, children }) {
    return (
        <>
            <div className={isModalOpen ? "todo-modal" : "hidden"}>
                <handleModal>{children}</handleModal>
            </div>
        </>
    );
};
const TodoModal = function ({ handleModal }) {
    return (
        <>
            <button type="button" className="todo-modal--close" onClick={handleModal}>
                &times;
            </button>
            <div className="input">
                <input type="text" className="input--main" placeholder="main" />
                <input type="text" className="input--sub" placeholder="sub" />
                <input type="date" className="input--start" placeholder="start" />
                <input type="date" className="input--deadline" placeholder="deadline" />
            </div>
            <button type="button" className="add-new-todo-btn">
                追加
            </button>
        </>
    );
};
